package auth

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/golang-jwt/jwt/v5"
	libauth "github.com/harusame0616/ijuku/apps/api/lib/auth"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

const testJWTSecret = "test-secret"

func newAuthTestVerifier(t *testing.T) *libauth.Verifier {
	t.Helper()
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		json.NewEncoder(w).Encode(map[string]any{"keys": []any{}})
	}))
	t.Cleanup(srv.Close)
	return libauth.NewVerifier(testJWTSecret, srv.URL)
}

func signAuthToken(t *testing.T, expired bool) string {
	t.Helper()
	exp := time.Now().Add(time.Hour)
	if expired {
		exp = time.Now().Add(-time.Hour)
	}
	token, err := jwt.NewWithClaims(jwt.SigningMethodHS256, jwt.MapClaims{
		"sub": "00000000-0000-0000-0000-000000000001",
		"exp": exp.Unix(),
	}).SignedString([]byte(testJWTSecret))
	require.NoError(t, err)
	return token
}

func TestCheckHandler(t *testing.T) {
	t.Run("Authorizationヘッダーがない場合401を返す", func(t *testing.T) {
		h := NewHandler(newAuthTestVerifier(t))
		req := httptest.NewRequest(http.MethodGet, "/v1/auth/check", nil)
		w := httptest.NewRecorder()
		h.CheckHandler(w, req)
		assert.Equal(t, http.StatusUnauthorized, w.Result().StatusCode)
	})

	t.Run("不正なトークンの場合401を返す", func(t *testing.T) {
		h := NewHandler(newAuthTestVerifier(t))
		req := httptest.NewRequest(http.MethodGet, "/v1/auth/check", nil)
		req.Header.Set("Authorization", "Bearer invalid.token.here")
		w := httptest.NewRecorder()
		h.CheckHandler(w, req)
		assert.Equal(t, http.StatusUnauthorized, w.Result().StatusCode)
	})

	t.Run("有効なトークンの場合200を返す", func(t *testing.T) {
		h := NewHandler(newAuthTestVerifier(t))
		token := signAuthToken(t, false)
		req := httptest.NewRequest(http.MethodGet, "/v1/auth/check", nil)
		req.Header.Set("Authorization", "Bearer "+token)
		w := httptest.NewRecorder()
		h.CheckHandler(w, req)
		assert.Equal(t, http.StatusOK, w.Result().StatusCode)
	})
}

